#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5,M=350;

int n,k,a[N],siz[M],mx[M][N];
bool del[N];
int len;

int cal(int x){
    return (x-1)/len+1;
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    len=sqrt(n);
    for(int i=1;i<=n;i++){
        siz[cal(i)]++;
        if(a[i]>a[mx[cal(i)][(i-len*(cal(i)-1))%k]])
            mx[cal(i)][(i-len*(cal(i)-1))%k]=i;
    }
    for(int i=1;i<=n;i++){
        int sum=0,p=0;
        for(int j=1;j<=cal(n);j++){
            if(a[mx[j][(k+1-sum)%k]]>a[p])
                p=mx[j][(k+1-sum)%k];
            sum=(sum+siz[j])%k;
        }
        printf("%d\n",a[p]);
        a[p]=0;
        siz[cal(p)]--;
        for(int i=len*(cal(p)-1)+1;i<=min(n,len*cal(p));i++)
            mx[cal(p)][(i-len*(cal(p)-1))%k]=0;
        for(int i=len*(cal(p)-1)+1,cnt=0;i<=min(n,len*cal(p));i++){
            cnt+=(a[i]>0);
            if(a[i]>a[mx[cal(p)][cnt%k]])
                mx[cal(p)][cnt%k]=i;
        }
    }
    return 0;
}
